const MenuIcon = () => (
  <svg aria-hidden="true" viewBox="0 0 24 24" focusable="false">
    <path d="M4 7h16" />
    <path d="M4 12h16" />
    <path d="M4 17h16" />
  </svg>
)

export function SiteHeader({
  activeView,
  isMobileMenuOpen,
  onNavigate,
  onToggleMobileMenu,
  onCloseMobileMenu,
}: SiteHeaderProps) {
  return (
    <header className="site-header">
      <button
        className="brand-mark"
        type="button"
        onClick={() => onNavigate('home')}
        aria-label="Volver al inicio"
      >
        <span className="brand-symbol">
          <BrandIcon />
        </span>
      </button>

      <nav className="main-nav" aria-label="Navegacion principal">
        <button
          className={activeView === 'search' ? 'is-active' : undefined}
          type="button"
          onClick={() => onNavigate('search')}
          aria-pressed={activeView === 'search'}
        >
          Buscar
        </button>

        <button
          className={activeView === 'publish' ? 'is-active' : undefined}
          type="button"
          onClick={() => onNavigate('publish')}
          aria-pressed={activeView === 'publish'}
        >
          Publicar
        </button>

        <a href="/perfil">Perfil</a>
      </nav>

      <button
        className="mobile-menu-toggle"
        type="button"
        onClick={onToggleMobileMenu}
        aria-expanded={isMobileMenuOpen}
        aria-controls="mobile-nav-menu"
        aria-label="Abrir menu"
      >
        <MenuIcon />
      </button>

      <div
        className={`mobile-nav-menu ${isMobileMenuOpen ? 'is-open' : ''}`}
        id="mobile-nav-menu"
      >
        <button
          className={activeView === 'search' ? 'is-active' : undefined}
          type="button"
          onClick={() => onNavigate('search')}
          aria-pressed={activeView === 'search'}
        >
          Buscar
        </button>

        <button
          className={activeView === 'publish' ? 'is-active' : undefined}
          type="button"
          onClick={() => onNavigate('publish')}
          aria-pressed={activeView === 'publish'}
        >
          Publicar
        </button>

        <a href="/perfil" onClick={onCloseMobileMenu}>
          Perfil
        </a>
      </div>
    </header>
  )
}